import { useState, useEffect } from "react";

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [result, setResult] = useState(null); // Stores the full response object
  const [loading, setLoading] = useState(true);

  // 1. FETCH QUESTIONS ON MOUNT
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const res = await fetch("http://localhost:3000/api/quiz");
        const data = await res.json();
        setQuestions(data);
      } catch (err) {
        console.error("Failed to load questions:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchQuestions();
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  // 2. SUBMIT ANSWERS
  const handleSubmit = async () => {
    try {
      const res = await fetch("http://localhost:3000/api/quiz/submit", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ answers: selected })
      });

      const data = await res.json();
      if (data.success) {
        setResult(data);
      }
    } catch (err) {
      alert("Error submitting quiz. Check server connection.");
    }
  };

  if (loading) return <div style={styles.container}>Loading Quizzly...</div>;

  return (
    <div style={styles.container}>
      <div style={styles.wrapper}>

        {/* HEADER */}
        <header style={styles.header}>
          <div>
            <h1 style={styles.logo}>QUIZZLY <span style={styles.vTag}>V1</span></h1>
            <div style={styles.glowBar} />
          </div>
          <div style={styles.userInfo}>
            <p style={styles.userName}>Harshith B</p>
            <p style={styles.userId}>23MIS0012</p>
          </div>
        </header>

        {/* CONDITIONAL RENDERING: SCORE VS QUIZ */}
        {!result ? (
          <>
            <div style={styles.quizArea}>
              {questions.map((q) => (
                <div key={q.id} style={styles.qCard}>
                  <h2 style={styles.qTitle}>
                    <span style={styles.qNum}>{q.id.toString().padStart(2, '0')}</span> 
                    {q.question}
                  </h2>
                  <div style={styles.optGrid}>
                    {q.options.map((opt) => {
                      const isActive = selected[q.id] === opt;
                      return (
                        <button
                          key={opt}
                          onClick={() => handleSelect(q.id, opt)}
                          style={{ ...styles.optBtn, ...(isActive ? styles.optActive : {}) }}
                        >
                          <div style={{ ...styles.dot, borderColor: isActive ? "#818cf8" : "#334155" }}>
                            {isActive && <div style={styles.dotInner} />}
                          </div>
                          {opt}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>

            <footer style={styles.footer}>
              <button onClick={handleSubmit} style={styles.submitBtn}>
                Finish Attempt
              </button>
            </footer>
          </>
        ) : (
          /* RESULT VIEW */
          <div style={styles.resultContainer}>
            <div style={styles.scoreCircle}>
              <h2 style={styles.scoreText}>{result.score} / {result.total}</h2>
              <p style={styles.percentText}>{result.percentage}% Accuracy</p>
            </div>
            <button onClick={() => window.location.reload()} style={styles.retryBtn}>
              Retake Quiz
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#020617",
    color: "#f1f5f9",
    fontFamily: "'Inter', system-ui, sans-serif",
    display: "flex",
    justifyContent: "center",
    overflow: "hidden",
    margin: 0,
  },
  wrapper: {
    width: "100%",
    maxWidth: "850px",
    height: "100%",
    display: "flex",
    flexDirection: "column",
    padding: "20px 30px",
    boxSizing: "border-box",
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "10px 0 25px 0",
  },
  logo: { fontSize: "20px", fontWeight: "900", margin: 0 },
  vTag: { color: "#6366f1", fontSize: "11px", fontWeight: "bold" },
  glowBar: { height: "3px", width: "30px", background: "#6366f1", marginTop: "4px", borderRadius: "10px", boxShadow: "0 0 12px #6366f1" },
  userInfo: { textAlign: "right" },
  userName: { fontSize: "13px", fontWeight: "600", margin: 0 },
  userId: { fontSize: "11px", color: "#64748b", margin: 0 },

  quizArea: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    gap: "18px",
    minHeight: 0,
    paddingBottom: "10px",
  },
  qCard: {
    flex: 1,
    background: "linear-gradient(145deg, #0f172a 0%, #030816 100%)",
    border: "1px solid #1e293b",
    borderRadius: "20px",
    padding: "24px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
  },
  qNum: { color: "#6366f1", marginRight: "12px", fontSize: "14px", fontWeight: "800" },
  qTitle: { fontSize: "17px", margin: "0 0 20px 0", fontWeight: "600" },
  optGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "12px" },
  optBtn: {
    all: "unset",
    padding: "14px 16px",
    background: "rgba(30, 41, 59, 0.3)",
    border: "1px solid #1e293b",
    borderRadius: "12px",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    fontSize: "14px",
    transition: "0.2s",
    color: "#94a3b8",
  },
  optActive: { borderColor: "#6366f1", background: "rgba(99, 102, 241, 0.08)", color: "#fff" },
  dot: { width: "14px", height: "14px", border: "2px solid", borderRadius: "50%", marginRight: "12px", display: "flex", alignItems: "center", justifyContent: "center" },
  dotInner: { width: "7px", height: "7px", background: "#6366f1", borderRadius: "50%" },

  footer: { padding: "15px 0", display: "flex", justifyContent: "center" },
  submitBtn: {
    all: "unset",
    background: "linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)",
    padding: "14px 70px",
    borderRadius: "14px",
    fontWeight: "700",
    cursor: "pointer",
    color: "white",
    boxShadow: "0 15px 25px -10px rgba(79, 70, 229, 0.4)",
  },

  /* RESULT STYLES */
  resultContainer: {
    flex: 1,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    gap: "30px",
  },
  scoreCircle: {
    width: "200px",
    height: "200px",
    borderRadius: "50%",
    border: "4px solid #6366f1",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    background: "rgba(99, 102, 241, 0.05)",
    boxShadow: "0 0 40px rgba(99, 102, 241, 0.2)",
  },
  scoreText: { fontSize: "32px", margin: 0, fontWeight: "900" },
  percentText: { fontSize: "14px", color: "#64748b", margin: 0 },
  retryBtn: {
    all: "unset",
    color: "#6366f1",
    fontWeight: "600",
    cursor: "pointer",
    textDecoration: "underline"
  }
};

export default App;
